   102→/**
   103→ * Detect pattern-based attributes using configured detectors
   104→ */
   105→function detectPatternAttributes(email: EmailMessage, config: AttributeDetectionStageConfig): DetectedAttribute[] {
   106→  const detectors = config.attributes?.detectors || [];
   107→  const detectedAttributes: DetectedAttribute[] = [];
   108→
   109→  for (const detector of detectors) {
   110→    try {
   111→      const detection = applyDetector(email, detector);
   112→      if (detection.detected) {
   113→        detectedAttributes.push({
   114→          attribute_name: detector.attribute,
   115→          attribute_value: detection.value,
   116→          detection_method: 'pattern',
   117→          detection_evidence: detection.evidence || 'Pattern match',
   118→          confidence: 0.8, // Default confidence for pattern matches
   119→        });
   120→      }
   121→    } catch (error) {
   122→      // Log error but continue processing
   123→      console.warn(`Error applying detector for ${detector.attribute}:`, error);
   124→    }
   125→  }
   126→
   127→  return detectedAttributes;
   128→}
