   130→/**
   131→ * Apply individual detector pattern to email content
   132→ */
   133→function applyDetector(
   134→  email: EmailMessage,
   135→  detector: AttributeDetector
   136→): { detected: boolean; value?: any; evidence?: string } {
   137→  const { field, operation, values } = detector;
   138→
   139→  // Get the field content to search
   140→  let searchContent = '';
   141→  switch (field) {
   142→  case 'body':
   143→    searchContent = email.bodyPlain || '';
   144→    break;
   145→  case 'subject':
   146→    searchContent = email.subject || '';
   147→    break;
   148→  case 'from.address':
   149→    searchContent = email.from?.email || '';
   150→    break;
   151→  case 'from.name':
   152→    searchContent = email.from?.name || '';
   153→    break;
   154→  default:
   155→    console.warn(`Unknown field type for detector: ${field}`);
   156→    return { detected: false };
   157→  }
   158→
   159→  // Apply detection operation
   160→  switch (operation) {
   161→  case 'contains_any':
   162→    for (const value of values) {
   163→      if (searchContent.toLowerCase().includes(value.toLowerCase())) {
   164→        return {
   165→          detected: true,
   166→          value: true,
   167→          evidence: `Found "${value}" in ${field}`,
   168→        };
   169→      }
   170→    }
   171→    break;
   172→
   173→  case 'regex_any':
   174→    for (const pattern of values) {
   175→      try {
   176→        const regex = new RegExp(pattern, 'ig'); // Add global flag for better matching
   177→        const match = searchContent.match(regex);
   178→        if (match) {
   179→          // For amount patterns, try to match the longest currency pattern
   180→          let bestMatch = match[0];
   181→          if (pattern.includes('\\$\\d+')) {
   182→            // Special handling for currency amounts - match full amounts with decimals
   183→            const fullAmountRegex = /\$\d+(?:\.\d{2})?/g;
   184→            const fullMatches = searchContent.match(fullAmountRegex);
   185→            if (fullMatches && fullMatches.length > 0) {
   186→              bestMatch = fullMatches[0]; // Use the first full amount match
   187→            }
   188→          }
   189→          return {
   190→            detected: true,
   191→            value: true,
   192→            evidence: `Regex "${pattern}" matched: "${bestMatch}" in ${field}`,
   193→          };
   194→        }
   195→      } catch (error) {
   196→        console.warn(`Invalid regex pattern: ${pattern}`, error);
   197→        continue;
   198→      }
   199→    }
   200→    break;
   201→
   202→  case 'starts_with':
   203→    for (const value of values) {
   204→      if (searchContent.toLowerCase().startsWith(value.toLowerCase())) {
   205→        return {
   206→          detected: true,
   207→          value: true,
   208→          evidence: `${field} starts with "${value}"`,
   209→        };
   210→      }
   211→    }
   212→    break;
   213→
   214→  case 'ends_with':
   215→    for (const value of values) {
   216→      if (searchContent.toLowerCase().endsWith(value.toLowerCase())) {
   217→        return {
   218→          detected: true,
   219→          value: true,
   220→          evidence: `${field} ends with "${value}"`,
   221→        };
   222→      }
   223→    }
   224→    break;
   225→
   226→  default:
   227→    console.warn(`Unknown operation type: ${operation}`);
   228→  }
   229→
   230→  return { detected: false };
   231→}
