   233→/**
   234→ * Detect derived attributes using logical rules
   235→ */
   236→function detectDerivedAttributes(email: EmailMessage, config: AttributeDetectionStageConfig): DetectedAttribute[] {
   237→  const settings = config.settings?.attribute_processing;
   238→  const detectedAttributes: DetectedAttribute[] = [];
   239→
   240→  // Derive self_sent attribute (if enabled, default true)
   241→  const detectSelfSent = !settings || settings.detect_self_sent !== false;
   242→  if (detectSelfSent) {
   243→    const selfSent = deriveSelfSent(email);
   244→    if (selfSent) {
   245→      detectedAttributes.push(selfSent);
   246→    }
   247→  }
   248→
   249→  // Domain-based derivations (if enabled, default true)
   250→  const resolveDomains = !settings || settings.resolve_domains !== false;
   251→  if (resolveDomains) {
   252→    // Derive from_financial_institution attribute
   253→    const financialInstitution = deriveFromFinancialInstitution(email, config);
   254→    if (financialInstitution) {
   255→      detectedAttributes.push(financialInstitution);
   256→    }
   257→
   258→    // Derive from_newsletter_source attribute
   259→    const newsletterSource = deriveFromNewsletterSource(email, config);
   260→    if (newsletterSource) {
   261→      detectedAttributes.push(newsletterSource);
   262→    }
   263→
   264→    // Derive from_logistics_carrier attribute
   265→    const logisticsCarrier = deriveFromLogisticsCarrier(email, config);
   266→    if (logisticsCarrier) {
   267→      detectedAttributes.push(logisticsCarrier);
   268→    }
   269→  }
   270→
   271→  return detectedAttributes;
   272→}
   273→
   274→/**
   275→ * Derive self_sent attribute - email sent from user to self
   276→ */
   277→function deriveSelfSent(email: EmailMessage): DetectedAttribute | null {
   278→  const userAddresses = getUserAddresses();
   279→  const fromAddress = email.from?.email?.toLowerCase();
   280→
   281→  // Check if from address is user address
   282→  if (!fromAddress || !userAddresses.includes(fromAddress)) {
   283→    return null;
   284→  }
   285→
   286→  // Check if all recipients are user addresses
   287→  const allRecipients: string[] = [];
   288→  if (email.to) {
   289→    allRecipients.push(...email.to.map((addr) => addr.email.toLowerCase()));
   290→  }
   291→  if (email.cc) {
   292→    allRecipients.push(...email.cc.map((addr) => addr.email.toLowerCase()));
   293→  }
   294→  if (email.bcc) {
   295→    allRecipients.push(...email.bcc.map((addr) => addr.email.toLowerCase()));
   296→  }
   297→
   298→  const allRecipientsAreUser = allRecipients.length > 0 && allRecipients.every((addr) => userAddresses.includes(addr));
   299→
   300→  // Check for List-Id header (exclude mailing lists)
   301→  const hasListId = email.payload?.headers?.some((header) => header.name.toLowerCase() === 'list-id');
   302→
   303→  if (allRecipientsAreUser && !hasListId) {
   304→    return {
   305→      attribute_name: 'self_sent',
   306→      attribute_value: true,
   307→      detection_method: 'derived',
   308→      detection_evidence: 'All recipients match user addresses',
   309→      confidence: 0.9,
   310→    };
   311→  }
   312→
   313→  return null;
   314→}
   315→
   316→/**
   317→ * Derive from_financial_institution attribute using domain lookup
   318→ */
   319→function deriveFromFinancialInstitution(
   320→  email: EmailMessage,
   321→  config: AttributeDetectionStageConfig
   322→): DetectedAttribute | null {
   323→  const fromAddress = email.from?.email?.toLowerCase();
   324→  if (!fromAddress) return null;
   325→
   326→  const fromDomain = extractBaseDomain(fromAddress);
   327→  const financialDomains = getFinancialDomains(config);
   328→
   329→  if (financialDomains.includes(fromDomain)) {
   330→    return {
   331→      attribute_name: 'from_financial_institution',
   332→      attribute_value: true,
   333→      detection_method: 'domain_lookup',
   334→      detection_evidence: fromDomain,
   335→      confidence: 0.85,
   336→    };
   337→  }
   338→
   339→  return null;
   340→}
   341→
   342→/**
   343→ * Derive from_newsletter_source attribute
   344→ */
   345→function deriveFromNewsletterSource(
   346→  email: EmailMessage,
   347→  config: AttributeDetectionStageConfig
   348→): DetectedAttribute | null {
   349→  const fromAddress = email.from?.email?.toLowerCase();
   350→  if (!fromAddress) return null;
   351→
   352→  const fromDomain = extractBaseDomain(fromAddress);
   353→  const newsletterDomains = getNewsletterDomains(config);
   354→
   355→  // Check domain match
   356→  if (newsletterDomains.includes(fromDomain)) {
   357→    return {
   358→      attribute_name: 'from_newsletter_source',
   359→      attribute_value: true,
   360→      detection_method: 'domain_lookup',
   361→      detection_evidence: fromDomain,
   362→      confidence: 0.8,
   363→    };
   364→  }
   365→
   366→  // Check List-Id header presence
   367→  const hasListId = email.payload?.headers?.some((header) => header.name.toLowerCase() === 'list-id');
   368→  if (hasListId) {
   369→    return {
   370→      attribute_name: 'from_newsletter_source',
   371→      attribute_value: true,
   372→      detection_method: 'derived',
   373→      detection_evidence: 'List-Id header present',
   374→      confidence: 0.85,
   375→    };
   376→  }
   377→
   378→  return null;
   379→}
   380→
   381→/**
   382→ * Derive from_logistics_carrier attribute
   383→ */
   384→function deriveFromLogisticsCarrier(
   385→  email: EmailMessage,
   386→  config: AttributeDetectionStageConfig
   387→): DetectedAttribute | null {
   388→  const fromAddress = email.from?.email?.toLowerCase();
   389→  if (!fromAddress) return null;
   390→
   391→  const fromDomain = extractBaseDomain(fromAddress);
   392→  const logisticsDomains = getLogisticsDomains(config);
   393→
   394→  if (logisticsDomains.includes(fromDomain)) {
   395→    return {
   396→      attribute_name: 'from_logistics_carrier',
   397→      attribute_value: true,
   398→      detection_method: 'domain_lookup',
   399→      detection_evidence: fromDomain,
   400→      confidence: 0.85,
   401→    };
   402→  }
   403→
   404→  return null;
   405→}
   406→
   407→/**
   408→ * Extract base domain from email address
   409→ */
   410→function extractBaseDomain(email: string): string {
   411→  const domainPart = email.split('@')[1];
   412→  if (!domainPart) return '';
   413→
   414→  // Handle subdomains - return main domain for common patterns
   415→  const parts = domainPart.split('.');
   416→  if (parts.length >= 2) {
   417→    return parts.slice(-2).join('.');
   418→  }
   419→  return domainPart;
   420→}
   421→
   422→/**
   423→ * Get user email addresses for self_sent detection
   424→ */
   425→function getUserAddresses(): string[] {
   426→  // In real implementation, this would come from user configuration
   427→  return ['user@gmail.com', 'scotthamilton77@gmail.com'];
   428→}
   429→
   430→/**
   431→ * Get financial domains for institution detection
   432→ */
   433→function getFinancialDomains(config: AttributeDetectionStageConfig): string[] {
   434→  return config.performance_cache?.financial_domains || [];
   435→}
   436→
   437→/**
   438→ * Get newsletter domains for source detection
   439→ */
   440→function getNewsletterDomains(config: AttributeDetectionStageConfig): string[] {
   441→  return config.performance_cache?.newsletter_domains || [];
   442→}
   443→
   444→/**
   445→ * Get logistics domains for carrier detection
   446→ */
   447→function getLogisticsDomains(config: AttributeDetectionStageConfig): string[] {
   448→  return config.performance_cache?.logistics_domains || [];
   449→}
   450→
   451→/**
   452→ * Class wrapper for AttributeDetectionStage to support test patterns
   453→ */
   454→export class AttributeDetectionStage {
   455→  async execute(email: EmailMessage, config: ProcessingConfig): Promise<AttributeDetectionResult> {
   456→    // Create a minimal classification context for the function
   457→    const context: ClassificationContext = {
   458→      emailId: email.id,
   459→      sessionId: email.processingSessionId || 'test_session',
   460→      categoryScores: {},
   461→      hardAssertionsApplied: [],
   462→      strongIndicatorSeeds: {},
   463→      stageTimings: {},
   464→      configurationRefs: {},
   465→    };
   466→
   467→    // Convert ProcessingConfig to AttributeDetectionStageConfig
   468→    const stageConfig: AttributeDetectionStageConfig = {
   469→      settings: config.settings,
   470→      attributes: config.attributes,
   471→      performance_cache: {
   472→        financial_domains: this._getFinancialDomains(),
   473→        newsletter_domains: this._getNewsletterDomains(),
   474→        logistics_domains: this._getLogisticsDomains(),
   475→      },
   476→    };
   477→
   478→    // Execute the stage function
   479→    const result = executeAttributeDetection(email, context, stageConfig);
   480→
   481→    // Preserve any previous stage data from the email input
   482→    const emailData = email as any;
   483→    if (emailData.candidate_scores) {
   484→      (result as any).candidate_scores = emailData.candidate_scores;
   485→    }
   486→    if (emailData.stage_results) {
   487→      (result as any).stage_results = emailData.stage_results;
   488→    }
   489→
   490→    return result;
   491→  }
   492→
   493→  // Mock methods for domain lookups (for testing)
   494→  _getUserAddresses(): string[] {
   495→    return getUserAddresses();
   496→  }
   497→
   498→  _getFinancialDomains(): string[] {
   499→    return ['chase.com', 'bankofamerica.com', 'paypal.com'];
   500→  }
   501→
   502→  _getNewsletterDomains(): string[] {
   503→    return ['medium.com', 'substack.com'];
   504→  }
   505→
   506→  _getLogisticsDomains(): string[] {
   507→    return ['fedex.com', 'ups.com', 'usps.com'];
   508→  }
   509→}
